// Binary Search concept:
// Sorted Array: [1, 3, 5, 7, 9, 11]
// Target: 9 -> Check middle (5), 9 > 5 so search only the right side.

function bubbleSort(arr) {
  let swapped;
  do {
    swapped = false;
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] > arr[i + 1]) {
        let temp = arr[i];
        arr[i] = arr[i + 1];
        arr[i + 1] = temp;
        swapped = true;
      }
    }
  }
 while (swapped);
  return arr;
}

